import { Outlet, NavLink } from "react-router-dom";

import { createUseStyles } from "react-jss";

const styles = createUseStyles({
  container: {
    display: "flex",

    listStyle: "none",
    gap: "10px",
  },
  li: {
    textDecoration: "none",
    color: "#58a6ff",
  },
  active: {
    color: "red",
  },
});

const Layout = () => {
  const classes = styles();
  return (
    <>
      <div>
        <ul className={classes.container}>
          <li>
            <NavLink
              className={({ isActive }) =>
                isActive ? `${classes.active}` : `${classes.li}`
              }
              to="html"
            >
              HTML
            </NavLink>
          </li>
          <li>
            <NavLink className={classes.li} to="css">
              CSS
            </NavLink>
          </li>
          <li>
            <NavLink className={classes.li} to="Figma">
              Figma
            </NavLink>
          </li>
        </ul>
      </div>
      <Outlet />
    </>
  );
};
export default Layout;
